sections.example:
// By value — does NOT modify original
void addOneCopy(int x) { x += 1; }

// By reference — DOES modify original
void addOneRef(int& x) { x += 1; }

// const reference — avoids copy, read-only
int sumVector(const vector<int>& nums) {
    int total = 0;
    for (int x : nums) total += x;
    return total;
}

int main() {
    int a = 5;
    addOneCopy(a);
    cout << a << endl;  // 5 (unchanged)
    addOneRef(a);
    cout << a << endl;  // 6 (modified)
}

exercise.starterCode:
void doubleAll(vector<int> nums) {
    for (int& x : nums) {
        x *= 2;
    }
}

int getSum(const vector<int> nums) {
    int total = 0;
    for (int x : nums) total += x;
    return total;
}

int main() {
    vector<int> nums = {1, 2, 3, 4, 5};
    doubleAll(nums);
    for (int x : nums) cout << x << " ";
    cout << endl;
    cout << getSum(nums) << endl;
    return 0;
}

