// Basic lambda
auto greet = [](const string& name) {
    cout << "Hi " << name << endl;
};
greet("Alice");

// Lambda with capture
int factor = 3;
auto multiply = [factor](int x) { return x * factor; };
cout << multiply(5) << endl;  // 15

// Lambda in sort
vector<int> nums = {5, 2, 8, 1};
sort(nums.begin(), nums.end(), [](int a, int b) {
    return a > b;  // descending
});

